// Calcule les 3 fenetres: J-1, J-3, J-7 (RDV passes)
const now = new Date();
function dayWindow(daysAgo) {
  const d = new Date(now);
  d.setDate(d.getDate() - daysAgo);
  d.setHours(0, 0, 0, 0);
  const end = new Date(d);
  end.setDate(end.getDate() + 1);
  return { from: d.toISOString(), to: end.toISOString() };
}
return [
  { json: { step: 'j1', type_log: 'relance_j1', ...dayWindow(1) } },
  { json: { step: 'j3', type_log: 'relance_j3', ...dayWindow(3) } },
  { json: { step: 'j7', type_log: 'relance_j7', ...dayWindow(7) } }
];

// Pour chaque RDV, on prepare un item avec le step (j1/j3/j7) present dans $input.first
const step = $('Compute Windows').item.json.step;
const typeLog = $('Compute Windows').item.json.type_log;
const rdvs = items.map(i => i.json);
const results = [];
for (const rdv of rdvs) {
  if (!rdv.clients || !rdv.clients.email) continue;
  const client = rdv.clients;
  const profile = rdv.profiles || {};
  let subject, prompt;
  if (step === 'j1') {
    subject = 'Suite a votre visite';
    prompt = `Redige un email court et chaleureux (3-4 phrases) pour remercier ${client.first_name} apres sa visite du bien "${rdv.title}" hier. Demande ses impressions sans pression. Signe ${profile.full_name || 'Alison'}. Pas de formule commerciale lourde.`;
  } else if (step === 'j3') {
    subject = 'Des nouvelles de votre projet ?';
    prompt = `Redige un email court (3-4 phrases) pour ${client.first_name} suite a sa visite du bien "${rdv.title}" il y a 3 jours. Demande s'il a pu reflechir, propose de repondre a ses questions. Ton amical et disponible. Signe ${profile.full_name || 'Alison'}.`;
  } else {
    subject = 'Toujours interesse ?';
    prompt = `Redige un email tres court (3 phrases) pour ${client.first_name} une semaine apres la visite du bien "${rdv.title}". Propose de revoir d'autres biens s'il n'est plus interesse par celui-ci. Ton bienveillant, pas insistant. Signe ${profile.full_name || 'Alison'}.`;
  }
  results.push({
    json: {
      step,
      type_log: typeLog,
      rdv_id: rdv.id,
      user_id: rdv.user_id,
      client_id: rdv.client_id,
      client_first_name: client.first_name,
      client_name: `${client.first_name} ${client.last_name}`,
      client_email: client.email,
      rdv_title: rdv.title,
      agent_name: profile.full_name || 'Alison Mendes',
      agent_business: profile.business_name || 'Visit & Smile',
      subject,
      prompt
    }
  });
}
return results;

// Fusionne le resultat du check avec les donnees de preparation
const sentCheck = items[0].json || [];
const prep = $('Prepare Relances').item.json;
if (Array.isArray(sentCheck) && sentCheck.length > 0) {
  return [];
}
return [{ json: prep }];

